SELECT * FROM emotion_anchor_events
WHERE user_id = #{userId}
ORDER BY start_time DESC
LIMIT #{limit}

SELECT * FROM emotion_anchor_events
WHERE user_id = #{userId}

    AND DATE(start_time) >= #{beginDate}


    AND DATE(start_time) < #{endDate}

ORDER BY start_time DESC
LIMIT #{offset}, #{limit}

SELECT trigger_reason, highlight_traits, ai_reflection, start_time
FROM emotion_anchor_events
WHERE user_id = #{userId}
ORDER BY start_time DESC
LIMIT #{limit}
